SELECT is_attack_ip, COUNT(*) AS total_login_attempts
FROM user_logins
GROUP BY is_attack_ip;

SELECT average_response_time
FROM login_statistics
WHERE stat_id = 1;

SELECT total_logins, successful_logins, AVG(average_response_time) AS avg_response_time
FROM login_statistics
WHERE total_logins > 90;

SELECT COUNT(ip_address) AS flagged_ips_count
FROM ip_blacklist
WHERE reason = 'Suspicious activity';

SELECT COUNT(DISTINCT user_id) AS account_takeover_users
FROM user_logins
WHERE is_account_takeover = 1;

SELECT geo_longitude, geo_latitude
FROM ip_geolocation
WHERE country_code = 'NO';

SELECT DISTINCT ip_address
FROM user_logins
WHERE is_attack_ip = 1;

SELECT ip_address
FROM ip_blacklist
WHERE source = 'internal';
